    print('Total records loaded:', len(data))

    # Process the data
    year_pattern = re.compile(r'\b(20\d{2})\b')
    records_by_year = {}
    level5_records = 0

    for i, record in enumerate(data):
        # Extract year
        date_str = record.get('publication_date', '')
        year_match = year_pattern.search(date_str)

        if year_match:
            year = int(year_match.group(1))

            # Extract CPC codes
            cpc_str = record.get('cpc', '[]')
            if cpc_str and cpc_str != '[]' and cpc_str != '':
                try:
                    cpc_list = json.loads(cpc_str)
                    for cpc_item in cpc_list:
                        code = cpc_item.get('code', '')
                        # Check if it's level 5 (has / and subgroup not 00)
                        if '/' in code:
                            parts = code.split('/')
                            if len(parts) == 2 and parts[1] != '00':
                                # This is level 5
                                if year not in records_by_year:
                                    records_by_year[year] = {}
                                records_by_year[year][code] = records_by_year[year].get(code, 0) + 1
                                level5_records += 1
                except json.JSONDecodeError:
                    continue

