    for year_data in records_by_year.values():
        all_codes.update(year_data.keys())

    print('Unique level 5 CPC codes:', len(all_codes))
    print('Sample codes:', list(all_codes)[:10])

    # Calculate EMA for each code
    smoothing_factor = 0.2
    codes_2022 = []

    for code in all_codes:
        ema = None
        max_ema = -1
        peak_year = None

        for year in all_years:
            count = records_by_year.get(year, {}).get(code, 0)

            if ema is None:
                ema = count
            else:
                ema = (smoothing_factor * count) + ((1 - smoothing_factor) * ema)

            if ema > max_ema:
                max_ema = ema
                peak_year = year

        if peak_year == 2022:
            codes_2022.append((code, max_ema))

    # Sort by EMA value
