if has_2022:
    year_code_counts = {}
    for rec in data:
        date_str = rec.get('publication_date', '')
        match = year_pattern.search(date_str)
        if match:
            year = int(match.group(1))
            cpc_str = rec.get('cpc', '[]')
            if cpc_str and cpc_str != '[]':
                try:
                    cpc_list = json.loads(cpc_str)
                    for item in cpc_list:
                        code = item.get('code', '')
                        if '/' in code and not code.endswith('/00'):
                            key = (year, code)
                            year_code_counts[key] = year_code_counts.get(key, 0) + 1
                except:
                    pass

    # Find codes that actually have 2022 data
    codes_with_2022 = set()
    for (year, code), count in year_code_counts.items():
        if year == 2022 and count > 0:
            codes_with_2022.add(code)

    print(f'\nLevel-5 codes with 2022 data: {len(codes_with_2022)}')
    print('Sample codes with 2022 data:', list(codes_with_2022)[:10])

    # Calculate simple growth ratio to find codes that peaked in 2022
    # Instead of EMA, compare 2022 count to average of previous years
    codes_peaked_2022 = []

    for code in codes_with_2022:
        # Get counts for all years for this code
        years = sorted(set(y for y, c in year_code_counts.keys() if c == code))
        counts = {y: year_code_counts.get((y, code), 0) for y in years}

        if 2022 in counts and counts[2022] > 0:
            # Calculate average of previous years
            prev_years = [y for y in years if y < 2022]
            if prev_years:
                avg_prev = sum(counts[y] for y in prev_years) / len(prev_years)
                if avg_prev > 0:
                    ratio = counts[2022] / avg_prev
                    if ratio > 1.5:  # 50% increase
                        codes_peaked_2022.append((code, ratio, counts[2022]))

    # Sort by ratio
    codes_peaked_2022.sort(key=lambda x: x[1], reverse=True)
    final_codes = [code for code, ratio, count in codes_peaked_2022]

    print(f'\nCodes that peaked in 2022 (ratio > 1.5): {len(final_codes)}')
    if final_codes:
        print('Top codes:')
        for code, ratio, count in codes_peaked_2022[:10]:
            print(f'  {code}: {count} patents, {ratio:.1f}x previous average')

    result = {'cpc_codes': final_codes}
else:
    result = {'cpc_codes': [], 'note': 'No 2022 data found'}

print('__RESULT__:')
print(json.dumps(result))"}

